var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"범은 기만의 짐승이다.","JPN":"虎は欺瞞のケモノだ。","ENG":"The Tiger is a deceiving Beast.","TWN":"老虎是欺瞞的野獸。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"자신의 약점이 무엇인지 알고 있다면, 놈은 오히려 함정을 파고 빈틈을 드러내겠지.","JPN":"己の弱点が分かるなら、やつはそこに罠を仕掛けて隙を見せるだろう。","ENG":"If we know its weakness, it'll lay a trap and expose a false opening.","TWN":"如果知道自己的弱點在哪，牠反而會設下陷阱，露出破綻。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"내가 놈의 앞발 쳐낼 테니, 넌 목덜미를 노리거라.","JPN":"俺がやつの前足を牽制する。お前は首元を狙え。","ENG":"I'll handle its forelegs. Go for the nape.","TWN":"你擋下牠的前爪，我來瞄準脖子。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"허면 그 함정이란 것은…?","JPN":"その罠とは……？","ENG":"Then the trap is…?","TWN":"那麼那個陷阱是…？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"제 아무리 무서운 범이라 한들, 결국 머리는 하나에 네 발 달린 짐승이다.","JPN":"いくらあの恐ろしい虎でも、所詮は頭1つに足が4つ付いたケモノに過ぎない。","ENG":"No matter how fearsome the Tiger, it's still a Beast with one head and four limbs, basically an animal.","TWN":"再怎麼可怕的老虎，終究只有一個頭和四條腿。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"등에서 팔이라도 돋지 않는 한, 놈이 숨겨둔 수가 무엇인진 뻔하지.","JPN":"背中から腕でも生えない限り、やつが隠している手は見え透いている。","ENG":"Unless it's got arms sprouting from its back, its options are obvious.","TWN":"只要牠背上不會長出手臂，牠藏起來的招數就很明顯。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"지금이다!","JPN":"今だ！","ENG":"Now!","TWN":"就是現在！"},"stage":{"bg":"MS_1501_2","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"합!","JPN":"はっ！","ENG":"Hup!","TWN":"喝！"},"stage":{"bg":"MS_1501_2","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"narration","speaker":null,"text":{"KOREA":"역시, 노리고 있던 건 그곳인가.","JPN":"やはり狙いはそこか。","ENG":"As expected, that's the spot you were aiming for all along.","TWN":"果然，你瞄準的就是那裡。"},"stage":{"bg":"MS_1501_2","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"BLACKMOUNTAIN_3","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"분명 범의 목을 노리고 달려들었으면서, 왜 뒤를 막은 거지?","JPN":"確かに虎の首を狙って飛び掛かったのに、なぜ背中を防御した？","ENG":"You rushed straight for the Tiger's neck. So why did you block the rear?","TWN":"你明明是衝著老虎的脖子來的，為什麼要擋住後面？"},"stage":{"bg":"BLACKMOUNTAIN_3","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그대의 살기가 너무 강하여, 눈치 챌 수밖에 없었네.","JPN":"そなたの殺気が強すぎて、気づかずにはいられなかった。","ENG":"The stench of your bloodlust was impossible to ignore. I couldn't help but notice.","TWN":"你的殺氣太強，我不得不察覺。"},"stage":{"bg":"BLACKMOUNTAIN_3","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…처음부터 함정인 줄 알고 있었구나.","JPN":"……最初から罠だと分かっていたのね。","ENG":"…You knew it was a trap from the start, didn't you?","TWN":"…你從一開始就知道這是陷阱。"},"stage":{"bg":"BLACKMOUNTAIN_3","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"큭…!","JPN":"くっ……！","ENG":"Kgh…!","TWN":"咳…！"},"stage":{"bg":"BLACKMOUNTAIN_3","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"당신에게 승산은 없어. 명달에게 범을 맡기고 들어온 건 큰 실수야.","JPN":"あなたに勝ち目はないわ。アカタツに虎を任せて入って来るなんて。","ENG":"You don't stand a chance. Leaving the Tiger to Myeongdal was a grave mistake.","TWN":"你沒有勝算。把老虎交給明達，然後衝進來是個大錯。"},"stage":{"bg":"BLACKMOUNTAIN_3","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"통계학적으로 보았을 때, 승산이 아주 없는 건 아닐세.","JPN":"統計学的に勝ち目はゼロではない。","ENG":"Statistically speaking, the odds aren't zero.","TWN":"從統計學來看，並非完全沒有勝算。"},"stage":{"bg":"BLACKMOUNTAIN_3","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_PRIDE"}}}},{"id":"L27_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"나도 한 번은 그댈 이겼잖은가.","JPN":"1度は某が勝ったではないか。","ENG":"I did beat you once, didn't I?","TWN":"我不也贏過你一次嗎？"},"stage":{"bg":"BLACKMOUNTAIN_3","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그 한 번은 운이 따라줬을 뿐.","JPN":"それは運がよかっただけよ。","ENG":"That was pure luck.","TWN":"那一次只是運氣好。"},"stage":{"bg":"BLACKMOUNTAIN_3","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"이번엔 내 주의를 돌릴 수단도 없을 테니까.","JPN":"今回は私の注意を引く手段もないでしょうから。","ENG":"And this time, you've got nothing to distract me.","TWN":"這次可沒有辦法轉移我的注意力了。"},"stage":{"bg":"BLACKMOUNTAIN_3","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"범의 피를 쓴다면… 또 모를 일이지.","JPN":"まだ分からんな……虎の血を使えば。","ENG":"If I tap into my Tiger Blood… who knows?","TWN":"如果使用老虎的血…或許就另當別論了。"},"stage":{"bg":"BLACKMOUNTAIN_3","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그럴 지도.","JPN":"そうかもね。","ENG":"Maybe so.","TWN":"也許吧。"},"stage":{"bg":"BLACKMOUNTAIN_3","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"하지만 그 힘을 쓰는 순간, 당신의 얼마 남지 않은 명줄도 거기서 끝나.","JPN":"でもその血を使った瞬間、あなたの残り僅かの命は尽きるわ。","ENG":"But the moment you use that power, the little time you have left will run out.","TWN":"但使用那股力量的瞬間，你剩下的壽命也會在此終結。"},"stage":{"bg":"BLACKMOUNTAIN_3","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"범을 눈앞에 두고 고작 창귀와의 싸움에서 목숨을 바칠 리가 없지.","JPN":"虎がすぐそこなのに、たかが倀鬼との戦いで命を捨てるなんてことはしないでしょう。","ENG":"You wouldn't waste your life fighting a ghost thrall when the Tiger's right there.","TWN":"你不可能把性命浪費在與倀鬼的戰鬥上，而老虎就在眼前。"},"stage":{"bg":"BLACKMOUNTAIN_3","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}}]`);export{e as default};